import React from 'react';
import { BrowserRouter, Routes, Route, Navigate } from 'react-router-dom';
import { AuthProvider } from './context/AuthContext';
import { ToastProvider } from './context/ToastContext';
import ProtectedRoute from './components/ProtectedRoute';
import Sidebar from './components/Sidebar';

import LoginPage          from './pages/LoginPage';
import RegisterPage       from './pages/RegisterPage';
import DashboardPage      from './pages/DashboardPage';
import ResumePage         from './pages/ResumePage';
import AnalyzerPage       from './pages/AnalyzerPage';
import ResultsPage        from './pages/ResultsPage';
import ReportPage         from './pages/ReportPage';
import JobBoardPage       from './pages/JobBoardPage';
import ApplicationsPage   from './pages/ApplicationsPage';
import AnalyticsPage      from './pages/AnalyticsPage';
import RecruiterDashboard from './pages/RecruiterDashboard';
import PostJobPage        from './pages/PostJobPage';
import MyJobsPage         from './pages/MyJobsPage';
import CandidatesPage     from './pages/CandidatesPage';

function AppLayout({ children }) {
  return (
    <div className="app-shell">
      <Sidebar />
      <main className="main-content">{children}</main>
    </div>
  );
}

function C(role, Page) {
  return (
    <ProtectedRoute role={role}>
      <AppLayout><Page /></AppLayout>
    </ProtectedRoute>
  );
}

export default function App() {
  return (
    <BrowserRouter>
      <AuthProvider>
        <ToastProvider>
          <Routes>
            <Route path="/login"    element={<LoginPage />} />
            <Route path="/register" element={<RegisterPage />} />
            <Route path="/"         element={<Navigate to="/login" replace />} />

            {/* Candidate */}
            <Route path="/dashboard"    element={C('candidate', DashboardPage)} />
            <Route path="/resume"       element={C('candidate', ResumePage)} />
            <Route path="/analyzer"     element={C('candidate', AnalyzerPage)} />
            <Route path="/results"      element={C('candidate', ResultsPage)} />
            <Route path="/report"       element={C('candidate', ReportPage)} />
            <Route path="/jobs"         element={C('candidate', JobBoardPage)} />
            <Route path="/applications" element={C('candidate', ApplicationsPage)} />
            <Route path="/analytics"    element={C('candidate', AnalyticsPage)} />

            {/* Recruiter */}
            <Route path="/recruiter"             element={C('recruiter', RecruiterDashboard)} />
            <Route path="/recruiter/post-job"    element={C('recruiter', PostJobPage)} />
            <Route path="/recruiter/my-jobs"     element={C('recruiter', MyJobsPage)} />
            <Route path="/recruiter/candidates"  element={C('recruiter', CandidatesPage)} />

            <Route path="*" element={<Navigate to="/login" replace />} />
          </Routes>
        </ToastProvider>
      </AuthProvider>
    </BrowserRouter>
  );
}
